// InmoLawyer - Extractor de Datos v2.0 (Mejorado)
const textoContrato = $input.first().json.text || $input.first().json.data || $input.first().json.body?.texto || '';

// Funciones auxiliares
const limpiarTexto = (str) => str ? str.trim().replace(/\s+/g, ' ') : null;
const extraerNumero = (str) => str ? str.replace(/[^0-9]/g, '') : null;
const parsearMoneda = (str) => {
  if (!str) return null;
  const limpio = str.replace(/[$\s]/g, '').replace(/\./g, '').replace(',', '.');
  return parseFloat(limpio) || null;
};

function extraerDatosContrato(texto) {
  const data = {
    arrendador: { nombre: null, documento: null, tipoDoc: null },
    arrendatario: { nombre: null, documento: null, tipoDoc: null },
    canon: null,
    fechaInicio: null,
    duracion: null,
    direccion: null,
    ciudad: null
  };

  // ===== ARRENDADOR =====
  // Buscar NIT primero (más confiable para sociedades)
  const patronNIT = /NIT[.:\s]*([\d.,\-]+)/i;
  const matchNIT = texto.match(patronNIT);
  if (matchNIT) {
    data.arrendador.documento = extraerNumero(matchNIT[1]);
    data.arrendador.tipoDoc = 'NIT';
  }

  // Buscar nombre de sociedad (SAS, SA, LTDA)
  const patronSociedad = /([A-ZÁÉÍÓÚÑ][A-ZÁÉÍÓÚÑ\s]+(?:SAS|S\.A\.S\.?|SA|S\.A\.?|LTDA|LIMITADA))/i;
  const matchSociedad = texto.match(patronSociedad);
  if (matchSociedad) {
    let nombreSociedad = matchSociedad[1];
    nombreSociedad = nombreSociedad.replace(/^(?:de\s+una\s+parte|entre|por\s+una\s+parte)\s+/i, '');
    data.arrendador.nombre = limpiarTexto(nombreSociedad);
  }

  // ===== ARRENDATARIO =====
  const patronArrendatario = /(?:EL\s+)?ARRENDATARIO[,:\s]+([A-ZÁÉÍÓÚÑ][a-záéíóúñA-ZÁÉÍÓÚÑ\s]+?),?\s*(?:mayor\s*de\s*edad)?[,\s]*(?:identificad[oa]\s*con\s*)?(?:c[ée]dula\s*(?:de\s*ciudadan[ií]a)?\s*(?:No\.?)?\s*|C\.?C\.?\s*(?:No\.?)?\s*)([\d.,]+)/i;
  const matchArrendatario = texto.match(patronArrendatario);

  if (matchArrendatario) {
    data.arrendatario.nombre = limpiarTexto(matchArrendatario[1]);
    data.arrendatario.documento = extraerNumero(matchArrendatario[2]);
    data.arrendatario.tipoDoc = 'C.C.';
  } else {
    // Patrón alternativo
    const patronAlt = /(?:y\s*de\s*otra\s*parte|otra\s*parte)\s+([A-ZÁÉÍÓÚÑ][a-záéíóúñA-ZÁÉÍÓÚÑ\s]+?),?\s*(?:mayor|identificad)/i;
    const matchAlt = texto.match(patronAlt);
    if (matchAlt) {
      data.arrendatario.nombre = limpiarTexto(matchAlt[1]);
    }

    const patronCC = /c[ée]dula\s*(?:de\s*ciudadan[ií]a)?\s*(?:No\.?)?\s*([\d.,]+)/gi;
    const matchesCC = [...texto.matchAll(patronCC)];
    if (matchesCC.length > 0) {
      data.arrendatario.documento = extraerNumero(matchesCC[0][1]);
      data.arrendatario.tipoDoc = 'C.C.';
    }
  }

  // ===== CANON =====
  const patronesCanon = [
    /canon\s*(?:mensual\s*)?(?:de\s*)?(?:arrendamiento)?[^$\d]*\$?\s*([\d.,]+)/i,
    /\$\s*([\d.,]+)\s*\)?[,\s]*(?:pesos)?/i,
    /suma\s*de[^$\d]*\$?\s*([\d.,]+)/i
  ];
  for (const patron of patronesCanon) {
    const matchCanon = texto.match(patron);
    if (matchCanon) {
      data.canon = parsearMoneda(matchCanon[1]);
      if (data.canon && data.canon > 100000) break;
    }
  }

  // ===== DIRECCIÓN =====
  const patronDireccion = /((?:CARRERA|CALLE|AVENIDA|DIAGONAL|TRANSVERSAL|CRA\.?|CL\.?|AV\.)\s*[\dA-Z]+\s*(?:No\.?|#)?\s*[\dA-Za-z\-]+(?:\s*(?:APARTAMENTO|APTO\.?|APT\.?|CASA|LOCAL|OFICINA|PISO)\s*[\dA-Za-z\-]+)?)/i;
  const matchDir = texto.match(patronDireccion);
  if (matchDir) {
    data.direccion = limpiarTexto(matchDir[1]);
  }

  // ===== CIUDAD =====
  const patronCiudad = /(?:ciudad\s*de\s*)?(Bogot[áa]\s*D\.?C\.?|Medell[íi]n|Cali|Barranquilla|Cartagena|Bucaramanga|C[úu]cuta|Pereira)/i;
  const matchCiudad = texto.match(patronCiudad);
  if (matchCiudad) {
    data.ciudad = limpiarTexto(matchCiudad[1]);
  }

  // ===== FECHA DE INICIO =====
  const meses = {'enero':'01','febrero':'02','marzo':'03','abril':'04','mayo':'05','junio':'06','julio':'07','agosto':'08','septiembre':'09','octubre':'10','noviembre':'11','diciembre':'12'};
  const patronFecha = /(\d{1,2})\s*(?:de)?\s*(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\s*(?:de|del)?\s*(\d{4})/i;
  const matchFecha = texto.match(patronFecha);
  if (matchFecha && meses[matchFecha[2].toLowerCase()]) {
    const dia = matchFecha[1].padStart(2, '0');
    const mes = meses[matchFecha[2].toLowerCase()];
    data.fechaInicio = `${matchFecha[3]}-${mes}-${dia}`;
  }

  // ===== DURACIÓN =====
  const patronDuracion = /(?:DOCE|SEIS|TRES|VEINTICUATRO)?\s*\(?\s*(\d+)\s*\)?\s*MESES?/i;
  const matchDuracion = texto.match(patronDuracion);
  if (matchDuracion) {
    data.duracion = parseInt(matchDuracion[1]);
  } else if (/un\s*a[ñn]o/i.test(texto)) {
    data.duracion = 12;
  }

  return data;
}

const datosExtraidos = extraerDatosContrato(textoContrato);

return {
  json: {
    textoContrato: textoContrato,
    datosExtraidos: datosExtraidos,
    archivoNombre: $input.first().json.fileName || 'contrato.pdf',
    timestamp: new Date().toISOString()
  }
};

// Parsear respuesta de la IA
const respuestaIA = $input.first().json.response || $input.first().json.text || $input.first().json;
const contratoId = $('Guardar Contrato en BD').first().json.id;

let analisis;
try {
  // Intentar parsear como JSON
  const jsonMatch = respuestaIA.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analisis = JSON.parse(jsonMatch[0]);
  } else {
    analisis = { alertas: [], score_riesgo: 50, resumen: 'Análisis no estructurado' };
  }
} catch (e) {
  analisis = { alertas: [], score_riesgo: 50, resumen: 'Error al parsear análisis' };
}

// Preparar alertas para insertar
const alertasParaInsertar = (analisis.alertas || []).map(alerta => ({
  contrato_id: contratoId,
  tipo: alerta.tipo || 'info',
  titulo: alerta.titulo || 'Alerta sin título',
  descripcion: alerta.descripcion || '',
  referencia_legal: alerta.referencia_legal || '',
  categoria: alerta.categoria || 'general',
  es_clausula_abusiva: alerta.es_clausula_abusiva || false,
  requiere_accion: alerta.tipo === 'danger'
}));

return {
  json: {
    contratoId: contratoId,
    analisis: analisis,
    alertas: alertasParaInsertar,
    scoreRiesgo: analisis.score_riesgo || 0,
    resumen: analisis.resumen || ''
  }
};

// Calcular incrementos según IPC
const contratoId = $input.first().json.contratoId;
const datosContrato = $('Extraer Datos del Contrato').first().json.datosExtraidos;

const IPC_HISTORICO = {
  2024: 5.20, 2023: 9.28, 2022: 13.12, 2021: 5.62,
  2020: 1.61, 2019: 3.80, 2018: 3.18, 2017: 4.09,
  2016: 5.75, 2015: 6.77, 2014: 3.66, 2013: 1.94
};

const incrementos = [];

if (datosContrato.canon && datosContrato.fechaInicio) {
  const fechaInicio = new Date(datosContrato.fechaInicio);
  const anioInicio = fechaInicio.getFullYear();
  const anioActual = new Date().getFullYear();

  let canonActual = datosContrato.canon;

  for (let anio = anioInicio; anio < anioActual; anio++) {
    const ipc = IPC_HISTORICO[anio] || 5.0;
    const incremento = canonActual * (ipc / 100);
    const canonNuevo = canonActual + incremento;

    incrementos.push({
      contrato_id: contratoId,
      anio: anio + 1,
      ipc_aplicado: ipc,
      canon_anterior: Math.round(canonActual),
      incremento: Math.round(incremento),
      canon_nuevo: Math.round(canonNuevo)
    });

    canonActual = canonNuevo;
  }
}

return incrementos.map(inc => ({ json: inc }));

// Calcular fechas importantes
const contratoId = $('Procesar Respuesta IA').first().json.contratoId;
const datosContrato = $('Extraer Datos del Contrato').first().json.datosExtraidos;

const fechasImportantes = [];

if (datosContrato.fechaInicio) {
  const fechaInicio = new Date(datosContrato.fechaInicio);
  const duracionMeses = datosContrato.duracion || 12;

  // Fecha de vencimiento
  const fechaVencimiento = new Date(fechaInicio);
  fechaVencimiento.setMonth(fechaVencimiento.getMonth() + duracionMeses);

  fechasImportantes.push({
    contrato_id: contratoId,
    tipo: 'vencimiento',
    fecha: fechaVencimiento.toISOString().split('T')[0],
    descripcion: 'Fecha de vencimiento del contrato',
    dias_anticipacion: 0
  });

  // Fecha para notificar desocupación (3 meses antes)
  const fechaNotifDesocupacion = new Date(fechaVencimiento);
  fechaNotifDesocupacion.setMonth(fechaNotifDesocupacion.getMonth() - 3);

  fechasImportantes.push({
    contrato_id: contratoId,
    tipo: 'desocupacion',
    fecha: fechaNotifDesocupacion.toISOString().split('T')[0],
    descripcion: 'Fecha límite para notificar desocupación (Art. 24 Ley 820)',
    dias_anticipacion: 90
  });

  // Próximo aniversario para incremento
  const hoy = new Date();
  const proximoAniversario = new Date(fechaInicio);
  proximoAniversario.setFullYear(hoy.getFullYear());
  if (proximoAniversario < hoy) {
    proximoAniversario.setFullYear(hoy.getFullYear() + 1);
  }

  // Fecha para notificar incremento (1 mes antes del aniversario)
  const fechaNotifIncremento = new Date(proximoAniversario);
  fechaNotifIncremento.setMonth(fechaNotifIncremento.getMonth() - 1);

  fechasImportantes.push({
    contrato_id: contratoId,
    tipo: 'incremento',
    fecha: fechaNotifIncremento.toISOString().split('T')[0],
    descripcion: 'Fecha límite para notificar incremento del canon',
    dias_anticipacion: 30
  });
}

return fechasImportantes.map(f => ({ json: f }));

